type SchemaCategory =
  | "Professional/Career"
  | "Startup/Investment"
  | "Legends"
  | "Lifestyle"
  | "Education/Learning"
  | "Creative Arts"
  | "Health & Mind";

function toSchemaCategory(category: string | undefined): SchemaCategory | undefined {
  const valid: SchemaCategory[] = [
    "Professional/Career",
    "Startup/Investment",
    "Legends",
    "Lifestyle",
    "Education/Learning",
    "Creative Arts",
    "Health & Mind",
  ];
  return valid.includes(category as SchemaCategory) ? (category as SchemaCategory) : undefined;
}


