/**
 * Reassign celebrity personas to their designated unique creator handles.
 * Run once after initial seed to fix existing data:
 *   bunx convex run --no-push convex/seedPersonas:fixCelebrityCreators
 */
export const fixCelebrityCreators = internalMutation({
  args: {},
  handler: async (ctx) => {
    const now = Date.now();
    const results: Array<{ slug: string; ok: boolean; handle?: string; error?: string }> = [];

    for (const [slug, handle] of Object.entries(CELEBRITY_CREATOR_MAP)) {
      try {
        // Ensure the user exists
        const existingUsers = await ctx.db
          .query("users")
          .withIndex("handle", (q) => q.eq("handle", handle))
          .collect();

        const userId =
          existingUsers[0]?._id ??
          (await ctx.db.insert("users", {
            handle,
            displayName: handle,
            role: "user",
            createdAt: now,
            updatedAt: now,
          }));

        // Find the skill by slug and update its ownerUserId
        const skill = await ctx.db
          .query("skills")
          .withIndex("by_slug", (q) => q.eq("slug", slug))
          .unique();

        if (skill) {
          await ctx.db.patch(skill._id, { ownerUserId: userId, updatedAt: now });

          // Also update skillSearchDigest
          const digests = await ctx.db
            .query("skillSearchDigest")
            .withIndex("by_skill", (q) => q.eq("skillId", skill._id))
            .collect();
          for (const digest of digests) {
            await ctx.db.patch(digest._id, { ownerUserId: userId, ownerHandle: handle });
          }

          results.push({ slug, ok: true, handle });
        } else {
          results.push({ slug, ok: false, error: "skill not found" });
        }
      } catch (e) {
        results.push({ slug, ok: false, error: e instanceof Error ? e.message : String(e) });
      }
    }

    const succeeded = results.filter((r) => r.ok).length;
    const failed = results.filter((r) => !r.ok).length;
    console.log(`fixCelebrityCreators: ${succeeded} updated, ${failed} failed`);
    if (failed > 0) console.log("Failures:", results.filter((r) => !r.ok));
    return { ok: true, succeeded, failed, results };
  },
});
